const registerWorldCupCountry = (slug, profile) => {
  const existing = window.VIAJEIO_COUNTRIES[slug];

  if (existing) {
    Object.assign(existing, {
      group: profile.group,
      name: profile.name || existing.name,
      flag: profile.flag || existing.flag,
      heroQuery: profile.heroQuery || existing.heroQuery,
      tagline: profile.tagline || existing.tagline,
    });
    return;
  }

  const name = profile.name;
  const heroQuery = profile.heroQuery || `${name} tourism`;
  const portraitQuery = profile.portraitQuery || `${name} landscape`;
  const cultureQuery = profile.cultureQuery || `${name} culture`;
  const footballQuery = profile.footballQuery || `${name} football stadium`;

  window.VIAJEIO_COUNTRIES[slug] = makeCountry({
    name,
    flag: profile.flag,
    group: profile.group,
    tagline: profile.tagline,
    heroQuery,
    portraitQuery,
    cultureQuery,
    footballQuery,
    overviewTitle: profile.overviewTitle || `${name}: territorio, cultura e futebol em rota de Copa.`,
    overview: profile.overview || `${name} aparece na Copa do Mundo de 2026 como um destino para observar paisagens, cidades, memoria historica, habitos cotidianos e a energia de uma selecao em um torneio global. A pagina funciona como uma introducao visual para entender o pais alem do placar.`,
    tourismTitle: profile.tourismTitle || `Roteiros essenciais para conhecer ${name}.`,
    tourismText: profile.tourismText || `A experiencia turistica combina capital, paisagens naturais, patrimonio cultural e pontos urbanos que ajudam a revelar a identidade do pais.`,
    spots: profile.spots || [
      [profile.capital || "Capital", "Centro politico, cultural e urbano do pais.", heroQuery],
      ["Paisagens", "Cenarios naturais que ajudam a definir a imagem do destino.", portraitQuery],
      ["Cultura local", "Mercados, ruas, museus e costumes que aproximam o visitante da vida cotidiana.", cultureQuery],
      ["Estadios", "A atmosfera do futebol como parte da experiencia de Copa.", footballQuery],
    ],
    cultureTitle: profile.cultureTitle || `Identidade, musica, memoria e vida cotidiana.`,
    culture: profile.culture || `${name} carrega uma cultura formada por historia, lingua, festas, esportes, culinaria e formas locais de receber. A experiencia visual mistura ruas, simbolos nacionais e expressoes populares.`,
    gastronomyTitle: profile.gastronomyTitle || `Sabores que contam o territorio.`,
    gastronomy: profile.gastronomy || `A gastronomia local combina ingredientes regionais, pratos de rua, receitas familiares e influencias historicas. Em uma viagem virtual, a comida ajuda a entender clima, costumes e encontros sociais.`,
    historyTitle: profile.historyTitle || `Uma historia que chega ao presente.`,
    history: profile.history || `${name} foi moldado por povos, migracoes, transformacoes politicas e relacoes com sua regiao. A historia do pais aparece em monumentos, cidades, memoria coletiva e simbolos nacionais.`,
    curiosities: profile.curiosities || [
      `${name} integra a fase de grupos da Copa do Mundo de 2026.`,
      "A selecao representa uma identidade nacional que vai alem do esporte.",
      "O turismo combina paisagens, cultura urbana e patrimonio historico.",
      "A gastronomia ajuda a contar a historia local.",
      "A torcida e os simbolos nacionais ganham destaque durante a Copa.",
    ],
    footballTitle: profile.footballTitle || `A selecao em clima de Copa do Mundo.`,
    football: profile.football || `O futebol em ${name} ganha forca em jogos internacionais, torcidas, camisas e narrativas de superacao. Na Copa, cada partida vira uma vitrine cultural e esportiva.`,
    gallery: profile.gallery || [
      ["Cidade", heroQuery],
      ["Paisagem", portraitQuery],
      ["Cultura", cultureQuery],
      ["Futebol", footballQuery],
    ],
  });
};

